/**
 * GET /api/builds/cover/$file
 *
 * Serves a build's wide promotional cover (build-covers/<id>-<ratio>.webp).
 * Covers are generated by xAI and stored as WebP in object storage; in
 * production buildCoverUrl points straight at the CDN, so this proxy is the
 * dev / no-CDN fallback that streams the object out of storage. Covers are
 * content-stable per id+ratio, so responses cache immutably.
 */

import { createFileRoute } from '@tanstack/react-router';
import { getObject } from '@/lib/storage/s3.server';
import { BUILD_COVER_PREFIX } from '@/lib/storage/keys';

// `<id>-<ratio>.webp` — safe filename chars only.
const FILE_RE = /^[A-Za-z0-9._-]+\.webp$/;

export const Route = createFileRoute('/api/builds/cover/$file')({
  server: {
    handlers: {
      GET: async ({ params }) => {
        const { file } = params;
        if (!file || file === '.' || file === '..' || !FILE_RE.test(file)) {
          return new Response('Not found', { status: 404 });
        }
        try {
          const object = await getObject(`${BUILD_COVER_PREFIX}${file}`);
          if (!object) {
            return new Response('Not found', { status: 404 });
          }
          return new Response(new Uint8Array(object.body), {
            headers: {
              'Content-Type': object.contentType || 'image/webp',
              'Cache-Control': 'public, max-age=31536000, immutable',
            },
          });
        } catch {
          return new Response('Not found', { status: 404 });
        }
      },
    },
  },
});
